sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;
    if (!newValue) return;

    var selectedDate = new Date(newValue);
    var now = new Date();

    if (selectedDate <= now) {
        g_form.showFieldMsg('needed_before', 'Needed Before must be a future date/time.', 'error');
    } else {
        g_form.hideFieldMsg('needed_before');
    }
}
